using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private static readonly List<Department> Departments =
    [
        new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
        new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Study of numbers, structures, and patterns." },
        new() { Id = 3, Code = "ENG", Name = "English", Description = "Study of literature, writing, and linguistics." },
        new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
        new() { Id = 5, Code = "HIST", Name = "History", Description = "Study of past events and their impact on society." },
    ];

    private static readonly List<Course> Courses =
    [
        new() { Id = 1, DepartmentId = 1, CourseCode = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen holds a PhD in Computer Science from MIT and has over 15 years of teaching experience in introductory programming.", IsFeatured = true },
        new() { Id = 2, DepartmentId = 1, CourseCode = "CS 201", Title = "Data Structures & Algorithms", Description = "A deep dive into data structures such as trees, graphs, and hash tables, as well as algorithm design and analysis.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park specializes in algorithm optimization and has published extensively in top-tier conferences.", IsFeatured = true },
        new() { Id = 3, DepartmentId = 1, CourseCode = "CS 310", Title = "Database Systems", Description = "Covers relational database design, SQL, transaction processing, and NoSQL systems.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Prof. Maria Gonzalez", InstructorBio = "Prof. Gonzalez worked as a database architect at Oracle for a decade before joining academia." },
        new() { Id = 4, DepartmentId = 1, CourseCode = "CS 450", Title = "Machine Learning", Description = "Introduction to supervised and unsupervised learning, neural networks, and practical applications of ML.", Credits = 4, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Alex Kumar", InstructorBio = "Dr. Kumar leads the university's AI research lab and has contributed to open-source ML frameworks." },
        new() { Id = 5, DepartmentId = 2, CourseCode = "MATH 101", Title = "Calculus I", Description = "Introduction to limits, derivatives, and integrals of single-variable functions.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Liu", InstructorBio = "Dr. Liu is an award-winning educator who has taught calculus for over 20 years.", IsFeatured = true },
        new() { Id = 6, DepartmentId = 2, CourseCode = "MATH 201", Title = "Linear Algebra", Description = "Vectors, matrices, determinants, eigenvalues, and linear transformations.", Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", InstructorName = "Dr. Emily Watson", InstructorBio = "Dr. Watson's research focuses on applied linear algebra in data science." },
        new() { Id = 7, DepartmentId = 2, CourseCode = "MATH 301", Title = "Probability & Statistics", Description = "Fundamentals of probability theory, random variables, distributions, and statistical inference.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Dr. Robert Liu", InstructorBio = "Dr. Liu is an award-winning educator who has taught calculus for over 20 years." },
        new() { Id = 8, DepartmentId = 3, CourseCode = "ENG 101", Title = "Composition & Rhetoric", Description = "Develop skills in academic writing, argumentation, and critical analysis of texts.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Prof. Diana Brooks", InstructorBio = "Prof. Brooks is a published author and former editor at a major literary journal." },
        new() { Id = 9, DepartmentId = 3, CourseCode = "ENG 250", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present.", Credits = 3, Schedule = "Tue/Thu 2:00–3:20 PM", InstructorName = "Dr. Michael Torres", InstructorBio = "Dr. Torres specializes in 20th-century American fiction and has authored three books on the subject.", IsFeatured = true },
        new() { Id = 10, DepartmentId = 4, CourseCode = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes laboratory sessions.", Credits = 4, Schedule = "Mon/Wed/Fri 8:00–8:50 AM + Lab Thu 2:00–4:50 PM", InstructorName = "Dr. Helen Nguyen", InstructorBio = "Dr. Nguyen is an experimental physicist whose work spans condensed matter and optics." },
        new() { Id = 11, DepartmentId = 4, CourseCode = "PHYS 201", Title = "General Physics II", Description = "Electricity, magnetism, optics, and modern physics. Includes laboratory sessions.", Credits = 4, Schedule = "Mon/Wed/Fri 9:00–9:50 AM + Lab Tue 2:00–4:50 PM", InstructorName = "Dr. Helen Nguyen", InstructorBio = "Dr. Nguyen is an experimental physicist whose work spans condensed matter and optics." },
        new() { Id = 12, DepartmentId = 5, CourseCode = "HIST 101", Title = "World History to 1500", Description = "Survey of major civilizations and events from ancient times through the late medieval period.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM", InstructorName = "Prof. Andrew Smith", InstructorBio = "Prof. Smith is a medievalist who has conducted archaeological research across Europe.", IsFeatured = true },
        new() { Id = 13, DepartmentId = 5, CourseCode = "HIST 201", Title = "Modern World History", Description = "From the Renaissance through the 21st century, focusing on political, social, and economic transformations.", Credits = 3, Schedule = "Mon/Wed 3:00–4:20 PM", InstructorName = "Dr. Linda Okafor", InstructorBio = "Dr. Okafor's research centers on post-colonial history and global migration patterns." },
    ];

    public List<Department> GetAllDepartments() => Departments;

    public Department? GetDepartment(int id) => Departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetAllCourses() => Courses;

    public List<Course> GetFeaturedCourses() => Courses.Where(c => c.IsFeatured).ToList();

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        Courses.Where(c => c.DepartmentId == departmentId).ToList();

    public Course? GetCourse(int id) => Courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = Courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }
}

