@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<div class="container">
    <h1 class="my-4">Enrollment Request</h1>

    @if (submitted)
    {
        <div class="alert alert-success">
            <h4>Request Submitted!</h4>
            <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for
                <strong>@(selectedCourseTitle)</strong> has been received. You will be notified by email once processed.</p>
        </div>
        <a href="/enroll" class="btn btn-primary">Submit Another Request</a>
        <a href="/courses" class="btn btn-outline-secondary ms-2">Browse Courses</a>
    }
    else
    {
        <p>Fill out the form below to request enrollment in a course.</p>

        <form method="post" @formname="enrollment" @onsubmit="HandleSubmit">
            <AntiforgeryToken />
            <div class="row">
                <div class="col-md-8 col-lg-6">
                    <div class="mb-3">
                        <label for="studentName" class="form-label">Full Name</label>
                        <input type="text" id="studentName" name="Model.StudentName" value="@Model.StudentName" class="form-control" required />
                        @if (errors.ContainsKey(nameof(Model.StudentName)))
                        {
                            <div class="text-danger">@errors[nameof(Model.StudentName)]</div>
                        }
                    </div>
                    <div class="mb-3">
                        <label for="studentId" class="form-label">Student ID</label>
                        <input type="text" id="studentId" name="Model.StudentId" value="@Model.StudentId" class="form-control" placeholder="e.g. AB123456" required />
                        @if (errors.ContainsKey(nameof(Model.StudentId)))
                        {
                            <div class="text-danger">@errors[nameof(Model.StudentId)]</div>
                        }
                    </div>
                    <div class="mb-3">
                        <label for="courseId" class="form-label">Course</label>
                        <select id="courseId" name="Model.CourseId" class="form-select" required>
                            <option value="0">-- Select a course --</option>
                            @foreach (var course in courses)
                            {
                                <option value="@course.Id" selected="@(Model.CourseId == course.Id)">@course.CourseCode — @course.Title</option>
                            }
                        </select>
                        @if (errors.ContainsKey(nameof(Model.CourseId)))
                        {
                            <div class="text-danger">@errors[nameof(Model.CourseId)]</div>
                        }
                    </div>
                    <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
                    <a href="/courses" class="btn btn-outline-secondary ms-2">Cancel</a>
                </div>
            </div>
        </form>
    }
</div>

@code {
    [SupplyParameterFromQuery] public int? CourseId { get; set; }
    [SupplyParameterFromForm] public EnrollmentRequest Model { get; set; } = new();

    private List<Course> courses = [];
    private Dictionary<string, string> errors = new();
    private bool submitted;
    private string selectedCourseTitle = string.Empty;

    protected override void OnInitialized()
    {
        courses = Catalog.GetAllCourses();
        if (CourseId.HasValue && Model.CourseId == 0)
            Model.CourseId = CourseId.Value;
    }

    private void HandleSubmit()
    {
        errors.Clear();
        var context = new System.ComponentModel.DataAnnotations.ValidationContext(Model);
        var results = new List<System.ComponentModel.DataAnnotations.ValidationResult>();
        if (!System.ComponentModel.DataAnnotations.Validator.TryValidateObject(Model, context, results, true))
        {
            foreach (var result in results)
            {
                foreach (var member in result.MemberNames)
                {
                    if (!errors.ContainsKey(member))
                        errors[member] = result.ErrorMessage ?? "Invalid";
                }
            }
            return;
        }

        var course = Catalog.GetCourse(Model.CourseId);
        selectedCourseTitle = course is not null ? $"{course.CourseCode} — {course.Title}" : "Unknown Course";
        submitted = true;
    }
}

